INSERT INTO content_posts (user_id, title, content, media_urls, social_platform, status, scheduled_at, published_at, views, likes) VALUES
(2, 'Новинка! Samsung Galaxy S23', 'Представляем новый флагман Samsung Galaxy S23! Камера 200 МП, мощный процессор, стильный дизайн. Уже в продаже! #Samsung #GalaxyS23 #Смартфон', ARRAY['/uploads/content/samsung-post.jpg'], 'instagram', 'published', '2024-01-15 10:00:00', '2024-01-15 10:00:00', 3456, 234),
(2, 'Игровой ноутбук ASUS ROG', 'Мощный игровой ноутбук ASUS ROG Strix G15 - идеален для геймеров! RTX 4060, 144Hz экран. Специальная цена! #ASUS #Gaming #Ноутбук', ARRAY['/uploads/content/asus-post.jpg'], 'vk', 'published', '2024-01-16 11:00:00', '2024-01-16 11:00:00', 2890, 189),
(2, 'Зимняя коллекция одежды', 'Новая коллекция зимней одежды уже в продаже! Теплые куртки, джинсы, обувь. Скидки до 30%! #Одежда #Зима #Скидки', ARRAY['/uploads/content/clothes-post.jpg'], 'telegram', 'published', '2024-01-17 09:00:00', '2024-01-17 09:00:00', 1234, 78),
(2, 'Стройматериалы со склада', 'Кирпич, цемент, профлист - все для стройки! Доставка по Москве и области. Лучшие цены! #Стройка #Материалы', ARRAY['/uploads/content/building-post.jpg'], 'vk', 'scheduled', '2024-02-25 10:00:00', NULL, 0, 0),
(2, 'Мебель для дома', 'Угловые диваны, столы, шкафы - создайте уют в доме! Качественная мебель по доступным ценам. #Мебель #Интерьер', ARRAY['/uploads/content/furniture-post.jpg'], 'instagram', 'draft', NULL, NULL, 0, 0),
(2, 'iPhone 15 Pro - Новинка!', 'Новый iPhone 15 Pro с титановым корпусом уже в продаже! Камера 48 МП, чип A17 Pro. Закажите сейчас! #iPhone #Apple #Новинка', ARRAY['/uploads/content/iphone-post.jpg'], 'instagram', 'published', '2024-01-17 12:00:00', '2024-01-17 12:00:00', 4567, 312),
(2, 'Автозапчасти в наличии', 'Масло, аккумуляторы, шины - все для вашего автомобиля! Широкий ассортимент, быстрая доставка. #Авто #Запчасти', ARRAY['/uploads/content/auto-post.jpg'], 'vk', 'published', '2024-01-20 09:00:00', '2024-01-20 09:00:00', 2345, 156),
(2, 'Спорт - это жизнь!', 'Гантели, коврики для йоги, мячи - все для активного образа жизни! Начните тренировки уже сегодня! #Спорт #Здоровье', ARRAY['/uploads/content/sport-post.jpg'], 'telegram', 'published', '2024-01-21 10:00:00', '2024-01-21 10:00:00', 1789, 98),
(2, 'Книги для души', 'Классическая и современная литература. Блокноты и ручки для записей. Погрузитесь в мир книг! #Книги #Чтение', ARRAY['/uploads/content/books-post.jpg'], 'vk', 'published', '2024-01-22 11:00:00', '2024-01-22 11:00:00', 1234, 67),
(2, 'Детские товары', 'LEGO, куклы, машинки - все для ваших детей! Качественные и безопасные игрушки. #Дети #Игрушки', ARRAY['/uploads/content/kids-post.jpg'], 'instagram', 'published', '2024-01-23 12:00:00', '2024-01-23 12:00:00', 3456, 234),
(2, 'Красота и здоровье', 'Косметика, парфюмерия, средства по уходу. Позаботьтесь о себе! #Красота #Здоровье', ARRAY['/uploads/content/beauty-post.jpg'], 'instagram', 'published', '2024-01-24 13:00:00', '2024-01-24 13:00:00', 2890, 189),
(2, 'Спортивное оборудование', 'Беговые дорожки, гантельные ряды - создайте свой спортзал дома! #Фитнес #Спортзал', ARRAY['/uploads/content/gym-post.jpg'], 'vk', 'published', '2024-01-25 14:00:00', '2024-01-25 14:00:00', 2345, 156),
(2, 'Бытовая техника', 'Роботы-пылесосы, кофеварки - сделайте жизнь проще! Современная техника для дома. #Техника #Дом', ARRAY['/uploads/content/tech-post.jpg'], 'telegram', 'published', '2024-01-26 15:00:00', '2024-01-26 15:00:00', 3456, 234),
(2, 'Холодильники и стиральные машины', 'Большая техника для вашего дома! Энергосберегающие модели, гарантия качества. #Техника #Дом', ARRAY['/uploads/content/appliances-post.jpg'], 'vk', 'published', '2024-01-27 16:00:00', '2024-01-27 16:00:00', 4567, 312),
(2, 'Инструменты для ремонта', 'Дрели, отвертки, все для домашнего ремонта! Качественные инструменты по доступным ценам. #Ремонт #Инструменты', ARRAY['/uploads/content/tools-post.jpg'], 'telegram', 'published', '2024-01-28 17:00:00', '2024-01-28 17:00:00', 1789, 98),
(2, 'Мода и стиль', 'Сумки, ремни, аксессуары - дополните свой образ! Стильные аксессуары из натуральной кожи. #Мода #Стиль', ARRAY['/uploads/content/fashion-post.jpg'], 'instagram', 'published', '2024-01-29 18:00:00', '2024-01-29 18:00:00', 2345, 156),
(2, 'Ювелирные изделия', 'Кольца, серьги из золота и серебра. Эксклюзивные украшения для особых моментов. #Ювелирка #Украшения', ARRAY['/uploads/content/jewelry-post.jpg'], 'instagram', 'published', '2024-01-30 19:00:00', '2024-01-30 19:00:00', 3456, 234),
(2, 'Товары для животных', 'Корм для собак и кошек, игрушки - все для ваших питомцев! Забота о животных. #Животные #Питомцы', ARRAY['/uploads/content/pets-post.jpg'], 'vk', 'published', '2024-01-31 20:00:00', '2024-01-31 20:00:00', 2890, 189),
(2, 'Сад и огород', 'Лопаты, семена - все для садоводов! Вырастите свой урожай. #Сад #Огород', ARRAY['/uploads/content/garden-post.jpg'], 'telegram', 'published', '2024-02-01 21:00:00', '2024-02-01 21:00:00', 1234, 67),
(2, 'Распродажа электроники', 'Скидки до 20% на всю электронику! Смартфоны, ноутбуки, планшеты. Успейте купить! #Распродажа #Электроника', ARRAY['/uploads/content/sale-electronics.jpg'], 'instagram', 'scheduled', '2024-02-10 10:00:00', NULL, 0, 0),
(2, 'Новая коллекция одежды', 'Весенняя коллекция уже в продаже! Свежие модели, актуальные цвета. #Мода #Весна', ARRAY['/uploads/content/spring-collection.jpg'], 'vk', 'scheduled', '2024-02-15 11:00:00', NULL, 0, 0),
(2, 'Скидки на стройматериалы', 'Специальные цены на кирпич, цемент, профлист. Стройте выгодно! #Стройка #Скидки', ARRAY['/uploads/content/building-sale.jpg'], 'telegram', 'scheduled', '2024-02-20 12:00:00', NULL, 0, 0),
(2, 'Мебель со скидкой', 'Распродажа мебели! Диваны, столы, шкафы по специальным ценам. #Мебель #Распродажа', ARRAY['/uploads/content/furniture-sale.jpg'], 'instagram', 'draft', NULL, NULL, 0, 0),
(2, 'Новинки в каталоге', 'Постоянно пополняем ассортимент! Следите за новинками в нашем каталоге. #Новинки #Каталог', ARRAY['/uploads/content/new-items.jpg'], 'vk', 'draft', NULL, NULL, 0, 0),
(2, 'Акция недели', 'Каждую неделю новые акции и скидки! Не пропустите выгодные предложения. #Акция #Скидки', ARRAY['/uploads/content/week-sale.jpg'], 'telegram', 'draft', NULL, NULL, 0, 0);

