-- Обновление счетчиков в таблице listings на основе аналитики
UPDATE listings SET 
  views = (SELECT COALESCE(SUM(views), 0) FROM listing_analytics WHERE listing_id = listings.id),
  favorites = (SELECT COALESCE(SUM(favorites), 0) FROM listing_analytics WHERE listing_id = listings.id)
WHERE id IN (SELECT DISTINCT listing_id FROM listing_analytics);
